// Simplifies (X / C) * M + (X % C) to X + (X / C) * (M - C), where M >= C.
// This uses the identity: (X / C) * C + (X % C) = X
// So: (X / C) * M + (X % C) = (X / C) * C + (X / C) * (M - C) + (X % C) = X + (X / C) * (M - C)
Value *InstCombinerImpl::SimplifyAddWithDivRem(BinaryOperator &I) {
  Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
  Value *X, *DivOrShl;
  APInt C, M;
  bool IsSigned;

  // Match pattern: (X / C) * M + (X % C)
  // Try LHS = (X / C) * M, RHS = (X % C)
  if (MatchMul(LHS, DivOrShl, M)) {
    Value *DivOp;
