      return Builder.CreateAdd(NewMul, X, I.getName());
    }
  }
  // Try RHS = (X / C) * M, LHS = (X % C)
  if (MatchMul(RHS, DivOrShl, M)) {
    Value *DivOp;
    APInt DivC;
    if (MatchDiv(DivOrShl, DivOp, DivC, IsSigned) &&
