  // or disjoint ((X / C) << N) (X % C) --> add (mul X (2^N - C)) X
  // or disjoint ((X / C) * M) (X % C) --> add (mul X (M - C)) X
  // This uses the identity: (X / C) * C + (X % C) = X
  Value *XVal, *DivOrShl;
  const APInt *C, *M;
  // Try pattern: or disjoint ((X / C) * M) (X % C)
  if (match(&I, m_c_DisjointOr(m_c_Mul(m_Value(DivOrShl), m_APInt(M)),
                               m_URem(m_Value(XVal), m_APInt(C))))) {
    Value *DivOp;
    const APInt *DivC;
    if ((match(DivOrShl, m_UDiv(m_Value(DivOp), m_APInt(DivC))) ||
         match(DivOrShl, m_LShr(m_Value(DivOp), m_APInt(DivC)))) &&
        DivOp == XVal && *C == *DivC) {
      // For shift, compute 2^N; for mul, use M directly
      APInt ActualM = *M;
      if (isa<ShlOperator>(DivOrShl) || match(DivOrShl, m_LShr(m_Value(), m_Value()))) {
        // This was actually a shift pattern - recompute M as 2^shift
        const APInt *ShiftAmt;
        if (match(DivOrShl, m_Shl(m_Value(), m_APInt(ShiftAmt))) ||
            match(DivOrShl, m_LShr(m_Value(), m_APInt(ShiftAmt)))) {
          ActualM = APInt::getOneValue(ShiftAmt->getBitWidth()) << *ShiftAmt;
        }
      }
      if (ActualM.uge(*C)) {
        APInt NewMulC = ActualM - *C;
        Value *NewMul = Builder.CreateMul(
            XVal, ConstantInt::get(Ty, NewMulC), "reass.mul", false, true);
        return BinaryOperator::CreateAdd(NewMul, XVal, I.getName());
      }
    }
  }
  // Try pattern: or disjoint ((X / C) << N) (X % C) where shift is direct
  if (match(&I, m_c_DisjointOr(m_Shl(m_Value(DivOrShl), m_APInt(M)),
                               m_URem(m_Value(XVal), m_APInt(C))))) {
    Value *DivOp;
